import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Layout from '../components/Layout';
import api from '../utils/api';
const prompts=['Show all Dell laptops under maintenance','Which employee has the most allocated assets?','Show assets whose warranty expires this month','What assets are idle?'];
export default function AssetAssistant(){const [question,setQuestion]=useState('');const [answer,setAnswer]=useState(null);const [loading,setLoading]=useState(false);const [report,setReport]=useState(null);const nav=useNavigate(); async function ask(q=question){if(!q.trim())return;setLoading(true);try{setAnswer((await api.askAssistant(q)).data)}catch(e){setAnswer({answer:e.message})}finally{setLoading(false)}} function voice(){const Speech=window.SpeechRecognition||window.webkitSpeechRecognition;if(!Speech){setAnswer({answer:'Voice input is not supported by this browser.'});return}const r=new Speech();r.lang='en-IN';r.onresult=e=>{const q=e.results[0][0].transcript;setQuestion(q);ask(q)};r.start()} async function generate(){setReport((await api.executiveReport('Monthly Operations')).data.report)} return <Layout title="AI Asset Assistant"><div className="mx-auto max-w-4xl space-y-5"><section className="rounded-2xl bg-ink-900 p-6 text-white"><p className="text-sm text-teal-300">Asset intelligence</p><h2 className="mt-1 text-2xl font-semibold">Ask questions in plain language</h2><form className="mt-5 flex gap-2" onSubmit={e=>{e.preventDefault();ask()}}><input value={question} onChange={e=>setQuestion(e.target.value)} placeholder="Ask about assets, maintenance, utilization, or warranties" className="min-w-0 flex-1 rounded-lg px-3 py-3 text-sm text-ink-900"/><button type="button" onClick={voice} className="rounded-lg border border-gray-500 px-3 text-sm">Voice</button><button className="rounded-lg bg-teal-500 px-4 text-sm font-medium">Ask</button></form><div className="mt-4 flex flex-wrap gap-2">{prompts.map(p=><button key={p} onClick={()=>{setQuestion(p);ask(p)}} className="rounded-full border border-gray-600 px-3 py-1 text-xs text-gray-200">{p}</button>)}</div></section>{loading&&<div className="rounded-xl border bg-white p-5 text-sm text-gray-500">Analyzing your asset data…</div>}{answer&&<section className="rounded-xl border bg-white p-5"><p className="text-sm leading-6 text-ink-900">{answer.answer}</p>{answer.degraded&&<p className="mt-2 text-xs text-amber-600">Using secure on-premise analytics because no LLM provider key is configured.</p>}{answer.results?.length>0&&<div className="mt-4 divide-y">{answer.results.map(a=><button key={a.id} onClick={()=>nav(`/assets/${a.id}`)} className="flex w-full justify-between py-3 text-left text-sm"><span><b>{a.assetTag}</b> · {a.name}</span><span className="text-gray-400">{a.status}</span></button>)}</div>}</section>}<section className="rounded-xl border bg-white p-5"><div className="flex items-center justify-between"><div><h3 className="font-semibold">Executive reports</h3><p className="text-sm text-gray-500">Generate a concise management-ready operations narrative.</p></div><button onClick={generate} className="rounded-lg border px-3 py-2 text-sm">Generate</button></div>{report&&<div className="mt-4 rounded-lg bg-gray-50 p-4 text-sm leading-6"><p>{report.summary}</p><ul className="mt-2 list-disc pl-5">{report.recommendations.map((r,i)=><li key={i}>{r.message}</li>)}</ul></div>}</section></div></Layout>}
