import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Layout from '../components/Layout';
import StatusBadge from '../components/StatusBadge';
import AssetTimeline from '../components/AssetTimeline';
import DocumentManager from '../components/DocumentManager';
import api from '../utils/api';

const date = v => v ? new Date(v).toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' }) : '—';
const status = v => ({ AVAILABLE:'Available', ALLOCATED:'Allocated', RESERVED:'Reserved', UNDER_MAINTENANCE:'Under Maintenance', LOST:'Lost', RETIRED:'Retired', DISPOSED:'Disposed' }[v] || v);
function Field({label,value}) { return <div><dt className="text-xs uppercase tracking-wide text-gray-400">{label}</dt><dd className="mt-1 text-sm font-medium text-ink-900">{value || '—'}</dd></div>; }
function Health({ insights }) { const h=insights?.health; const m=insights?.maintenance; if (!h) return null; const tone=h.score>=85?'bg-emerald-500':h.score>=65?'bg-teal-500':h.score>=40?'bg-amber-500':'bg-red-500'; return <div className="grid gap-4 sm:grid-cols-2"><div className="rounded-xl border bg-white p-5"><p className="text-xs font-semibold uppercase tracking-wider text-gray-400">Asset health</p><div className="mt-3 flex items-end gap-3"><span className="text-4xl font-semibold text-ink-900">{h.score}</span><span className="mb-1 text-sm text-gray-500">/100 · {h.label}</span></div><div className="mt-3 h-2 overflow-hidden rounded bg-gray-100"><div className={`h-full ${tone}`} style={{width:`${h.score}%`}} /></div><p className="mt-3 text-xs text-gray-500">{h.factors.repairs} repairs · {h.factors.ageYears} years old · warranty {h.factors.warrantyActive?'active':'expired'}</p></div><div className="rounded-xl border bg-white p-5"><p className="text-xs font-semibold uppercase tracking-wider text-gray-400">Predictive maintenance</p><p className="mt-3 text-lg font-semibold text-ink-900">{m.risk}</p><p className="mt-1 text-sm text-gray-500">{m.recommendation}</p><p className="mt-3 text-xs text-gray-400">Recommended: {date(m.recommendedMaintenanceDate)} · {m.failureCount} completed repairs</p></div></div>; }
export default function AssetDetail() {
 const {id}=useParams(); const navigate=useNavigate(); const [data,setData]=useState({}); const [loading,setLoading]=useState(true); const [tab,setTab]=useState('timeline');
 const load=useCallback(async()=>{setLoading(true);try{const [asset,events,insights,docs]=await Promise.all([api.getAssetPassport(id),api.getAssetTimeline(id),api.getAssetInsights(id),api.getDocuments(id)]);setData({asset:asset.data.passport,events:events.data.events,insights:insights.data.insights,documents:docs.data.documents});}catch(e){alert(e.message);navigate('/assets')}finally{setLoading(false)}},[id,navigate]); useEffect(()=>{load()},[load]);
 if(loading)return <Layout title="Asset Passport"><div className="animate-pulse space-y-5"><div className="h-32 rounded-xl bg-gray-100"/><div className="h-64 rounded-xl bg-gray-100"/></div></Layout>;
 const a=data.asset, allocation=a.allocations?.find(x=>x.isActive);
 async function regenerate(){if(!window.confirm('Regenerate QR? Existing code will stop working.'))return;const r=await api.regenerateQR(id);setData(d=>({...d,asset:{...d.asset,...r.data.asset}}));}
 return <Layout title="Digital Asset Passport"><button onClick={()=>navigate('/assets')} className="mb-5 text-sm text-gray-500 hover:text-ink-900">← Back to Assets</button><div className="rounded-2xl bg-ink-900 p-6 text-white shadow-sm"><div className="flex flex-wrap justify-between gap-5"><div><p className="font-mono text-xs text-teal-300">{a.assetTag}</p><h2 className="mt-1 text-2xl font-semibold">{a.name}</h2><p className="mt-1 text-sm text-gray-300">{a.category?.name} · {a.location || 'Location not set'}</p></div><div className="flex items-center gap-4"><StatusBadge status={status(a.status)}/>{a.qrCodeUrl&&<img src={a.qrCodeUrl} className="h-20 w-20 rounded bg-white p-1" alt="Asset QR"/>}</div></div></div><div className="mt-6 grid gap-6 xl:grid-cols-3"><div className="space-y-5 xl:col-span-2"><Health insights={data.insights}/><section className="rounded-xl border bg-white p-5"><h3 className="font-semibold text-ink-900">Asset information</h3><dl className="mt-4 grid grid-cols-2 gap-x-8 gap-y-5 md:grid-cols-3"><Field label="Manufacturer / model" value={a.customFields?.manufacturer ? `${a.customFields.manufacturer} ${a.customFields.model || ''}` : a.name}/><Field label="Serial number" value={a.serialNumber}/><Field label="Department" value={a.department?.name || a.customFields?.department}/><Field label="Vendor" value={a.vendor?.name}/><Field label="Purchase date" value={date(a.acquisitionDate)}/><Field label="Purchase cost" value={a.acquisitionCost ? `₹${Number(a.acquisitionCost).toLocaleString('en-IN')}` : null}/><Field label="Warranty" value={date(a.warrantyExpiry)}/><Field label="Condition" value={a.condition}/><Field label="Invoice" value={a.invoiceNumber}/></dl></section><section className="rounded-xl border bg-white p-5"><div className="mb-4 flex gap-4 border-b"><button onClick={()=>setTab('timeline')} className={`pb-3 text-sm font-medium ${tab==='timeline'?'border-b-2 border-teal-500 text-teal-700':'text-gray-500'}`}>Lifecycle timeline</button><button onClick={()=>setTab('documents')} className={`pb-3 text-sm font-medium ${tab==='documents'?'border-b-2 border-teal-500 text-teal-700':'text-gray-500'}`}>Documents ({data.documents?.length||0})</button></div>{tab==='timeline'?<AssetTimeline events={data.events}/>:<DocumentManager assetId={id} documents={data.documents||[]} onChange={load}/>}</section></div><aside className="space-y-5"><section className="rounded-xl border bg-white p-5"><p className="text-xs font-semibold uppercase tracking-wider text-gray-400">Assignment</p>{allocation?<dl className="mt-4 space-y-4"><Field label="Current holder" value={allocation.allocatedToUser?.name}/><Field label="Email" value={allocation.allocatedToUser?.email}/><Field label="Expected return" value={date(allocation.expectedReturnDate)}/></dl>:<p className="mt-4 text-sm text-gray-400">Available and not assigned.</p>}</section><section className="rounded-xl border bg-white p-5"><p className="text-xs font-semibold uppercase tracking-wider text-gray-400">QR controls</p><div className="mt-4 space-y-2"><a href={api.getQRDownloadUrl(id)} className="block rounded-lg bg-ink-900 px-3 py-2 text-center text-sm text-white">Download QR</a><button onClick={regenerate} className="w-full rounded-lg border px-3 py-2 text-sm">Regenerate QR</button></div></section></aside></div></Layout>;
}
